#include <stdio.h>
#include <stdlib.h>
#define MAX_N 1000
#define MAX_M 1000

int max_colors(int n, int** labels) {
    int max_colors = 0;
    for (int i = 0; i < n; i++) {
        int degree = 0;
        for (int j = 0; j < labels[i][0]; j++) {
            degree++;
        }
        for (int j = 0; j < n; j++) {
            for (int k = 1; k <= labels[j][0]; k++) {
                if ((j + labels[j][k]) % n == i) {
                    degree++;
                }
            }
        }
        max_colors = (max_colors > degree) ? max_colors : degree;
    }
    return max_colors;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int n;
        scanf("%d", &n);
        int** labels = (int**)malloc(n * sizeof(int*));
        for (int i = 0; i < n; i++) {
            labels[i] = (int*)malloc((MAX_M + 1) * sizeof(int));
            scanf("%d", &labels[i][0]);
            for (int j = 1; j <= labels[i][0]; j++) {
                scanf("%d", &labels[i][j]);
            }
        }
        int result = max_colors(n, labels);
        printf("%d\n", result);
        for (int i = 0; i < n; i++) {
            free(labels[i]);
        }
        free(labels);
    }
    return 0;
}

