import java.util.Scanner;
public class Main {
    public static int max_colors(int n, int[][] labels) {
        int max_colors = 0;
        for (int i = 0; i < n; i++) {
            int degree = labels[i].length;
            for (int j = 0; j < n; j++) {
                for (int k = 0; k < labels[j].length; k++) {
                    if ((j + labels[j][k]) % n == i) {
                        degree++;
                    }
                }
            }
            max_colors = (max_colors > degree) ? max_colors : degree;
        }
        return max_colors;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int n = scanner.nextInt();
            int[][] labels = new int[n][];
            for (int i = 0; i < n; i++) {
                int m = scanner.nextInt();
                labels[i] = new int[m];
                for (int j = 0; j < m; j++) {
                    labels[i][j] = scanner.nextInt();
                }
            }
            int result = max_colors(n, labels);
            System.out.println(result);
        }
    }
}

